manifest_content:
{
  "name": "design-monorepo",
  "private": true,
  "workspaces": [
    "packages/*"
  ],
  "packageManager": "bun@1.3.9",
  "scripts": {
    "build": "turbo build",
    "test": "turbo test",
    "lint": "turbo lint",
    "cli": "bun run packages/cli/src/index.ts"
  },
  "devDependencies": {
    "@types/node": "^25.6.0",
    "bun-types": "^1.3.12",
    "turbo": "latest",
    "typescript": "latest"
  }
}

{
  "name": "open-generative-ai",
  "description": "Open-source alternative to HF AI — AI image, video, cinema and lip sync studio",
  "homepage": "https://github.com/Anil-matcha/Open-Generative-AI",
  "private": true,
  "version": "2.0.0",
  "license": "MIT",
  "workspaces": [
    "packages/studio",
    "packages/Vibe-Workflow/packages/workflow-builder",
    "packages/Open-Poe-AI/packages/agents",
    "packages/Open-AI-Design-Agent/packages/design-agent"
  ],
  "scripts": {
    "dev": "next dev",
    "build": "next build",
    "start": "next start",
    "lint": "next lint",
    "build:studio": "npm run build -w studio",
    "build:workflow": "npm run build -w workflow-builder",
    "build:agent": "npm run build -w ai-agent",
    "build:packages": "npm run build:workflow && npm run build:agent && npm run build:studio",
    "setup": "git submodule update --init --recursive && npm install && npm run build:packages",
    "vite:dev": "vite",
    "vite:build": "vite build",
    "electron:dev": "npm run vite:build && electron .",
    "electron:build": "vite build && electron-builder --mac",
    "electron:build:win": "vite build && electron-builder --win",
    "electron:build:linux": "vite build && electron-builder --linux",
    "electron:build:linux:dir": "vite build && electron-builder --linux dir",
    "electron:build:linux:arm64:dir": "vite build && electron-builder --linux dir --arm64",
    "stage:local-ai": "node scripts/stage-local-ai-binary.js",
    "package:linux:deb": "node scripts/package-linux-deb.js",
    "package:linux:deb:arm64": "node scripts/package-linux-deb.js --arch arm64",
    "package:linux:deb:x64": "node scripts/package-linux-deb.js --arch x64",
    "electron:build:all": "vite build && electron-builder --mac --win --linux"
  },
  "build": {
    "appId": "ai.generative.open",
    "productName": "Open Generative AI",
    "copyright": "Copyright © 2025",
    "directories": {
      "output": "release"
    },
    "afterPack": "./afterPack.js",
    "files": [
      "dist/**/*",
      "electron/**/*"
    ],
    "extraResources": [
      {
        "from": "build/local-ai",
        "to": "local-ai",
        "filter": [
          "**/*"
        ]
      }
    ],
    "mac": {
      "category": "public.app-category.graphics-design",
      "icon": "public/banner.png",
      "gatekeeperAssess": false,
      "target": [
        {
          "target": "dmg",
          "arch": [
            "x64",
            "arm64"
          ]
        }
      ]
    },
    "win": {
      "icon": "public/banner.png",
      "signAndEditExecutable": false,
      "target": [
        {
          "target": "nsis",
          "arch": [
            "x64"
          ]
        }
      ]
    },
    "nsis": {
      "oneClick": false,
      "allowToChangeInstallationDirectory": true,
      "include": "build/installer.nsh"
    },
    "linux": {
      "icon": "public/banner.png",
      "category": "Utility",
      "maintainer": "Open Generative AI Team",
      "extraFiles": [
        {
          "from": "build/linux/apparmor.profile",
          "to": "resources/apparmor.profile"
        }
      ],
      "target": [
        {
          "target": "AppImage",
          "arch": [
            "x64"
          ]
        },
        {
          "target": "deb",
          "arch": [
            "x64"
          ]
        }
      ]
    }
  },
  "dependencies": {
    "axios": "^1.7.0",
    "next": "^15.0.0",
    "react": "^19.0.0",
    "react-dom": "^19.0.0",
    "react-hot-toast": "^2.4.1",
    "studio": "*",
    "workflow-builder": "file:./packages/Vibe-Workflow/packages/workflow-builder",
    "ai-agent": "file:./packages/Open-Poe-AI/packages/agents"
  },
  "devDependencies": {
    "@eslint/eslintrc": "^3",
    "@tailwindcss/vite": "^4.1.18",
    "autoprefixer": "^10.4.24",
    "electron": "^33.4.11",
    "electron-builder": "^25.1.8",
    "eslint": "^9",
    "eslint-config-next": "^15.0.0",
    "postcss": "^8.5.6",
    "tailwindcss": "^3.4.0",
    "vite": "^5.4.0"
  },
  "main": "electron/main.js"
}

[workspace]
resolver = "2"
members = [
    "crates/agentos-protocol",
    "crates/agentos-sidecar",
    # NOTE: crates/agentos-sidecar-browser is intentionally excluded from the
    # default workspace members. It path/version-depends on
    # `secure-exec-sidecar-browser`, which secure-exec does not publish to
    # crates.io. It is unrelated to the actor-plugin cdylib + sidecar binary the
    # preview ships. Re-add it once secure-exec publishes the browser crate.
    "crates/client",
    "crates/agentos-actor-plugin",
]

[workspace.package]
version = "0.2.0-rc.3"
edition = "2021"
license = "Apache-2.0"
repository = "https://github.com/rivet-dev/agent-os"

# AgentOS crates are published as a lock-step chain. Secure Exec is consumed as
# normal crates.io dependencies so CI/publish builds do not need a sibling
# checkout.
[workspace.dependencies]
agentos-bridge = { package = "secure-exec-bridge", version = "0.3.2" }
agentos-protocol = { path = "crates/agentos-protocol", version = "0.2.0-rc.3" }
agentos-sidecar = { path = "crates/agentos-sidecar", version = "0.2.0-rc.3" }
agentos-sidecar-browser = { path = "crates/agentos-sidecar-browser", version = "0.2.0-rc.3" }
agentos-kernel = { package = "secure-exec-kernel", version = "0.3.2" }
agentos-execution = { package = "secure-exec-execution", version = "0.3.2" }
agentos-v8-runtime = { package = "secure-exec-v8-runtime", version = "0.3.2" }
secure-exec-client = { version = "0.3.2" }
secure-exec-bridge = { version = "0.3.2" }
secure-exec-sidecar = { version = "0.3.2" }
secure-exec-vm-config = { version = "0.3.2" }
vbare = "0.0.4"
vbare-compiler = { package = "rivet-vbare-compiler", version = "0.0.5" }
